class Solution:
    def buddyStrings(self, s, goal):
        if len(s) != len(goal):
            return False
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n):
                t = list(s)
                t[i], t[j] = t[j], t[i]
                if ''.join(t) == goal:
                    return True
        return False

